	/**
	 * Install a store-provided gate for background rebuilds. Returning {@code false} pauses refresh-thread rebuild
	 * attempts until the gate opens again.
	 */
	public void setRebuildAllowedSupplier(BooleanSupplier supplier) {
		this.rebuildAllowedSupplier = supplier;
	}

	public void startBackgroundRefresh(int stalenessThreshold) {
		if (running) {
			return;
		}
		running = true;

		refresher = new Thread(() -> {
			while (running) {
				if (!isRebuildAllowed()) {
					if (!waitForRefreshDelay()) {
						break;
					}
					continue;
				}

				if (rebuildRequired.get()) {
					if (!waitForBackgroundRebuildQuietPeriod()) {
						break;
					}
					try {
						rebuildIfStillRequired();
					} catch (Throwable t) {
						if (!running || wasInterrupted(t)) {
							notifyReadyWaiters();
							logger.debug("Interrupted while rebuilding join estimator", t);
							break;
						}
						logger.error("Error while rebuilding join estimator", t);
					}
					if (!waitForRefreshDelay()) {
						break;
					}
					continue;
				}

				if (!sketchesLoaded && persistenceEnabled && hasSnapshotAvailable(persistenceFile)) {
					try {
						tryLoadFromDisk();
					} catch (Throwable t) {
						logger.error("Error while loading join estimator snapshot", t);
					}
					if (!waitForRefreshDelay()) {
						break;
					}
					continue;
				}

				if (sketchesLoaded) {
					try {
						flushPendingIncremental();
						notifyReadyWaiters();
					} catch (Throwable t) {
						if (!running || wasInterrupted(t)) {
							notifyReadyWaiters();
							logger.debug("Interrupted while flushing incremental join estimator updates", t);
							break;
						}
						logger.error("Error while flushing incremental join estimator updates", t);
					}
				}

				boolean stale = isStale(stalenessThreshold);
				if (!stale) {
					if (!waitForRefreshDelay()) {
						break;
					}
					continue;
				}

				try {
					if (!waitForBackgroundRebuildQuietPeriod()) {
						break;
					}
					rebuild();
				} catch (Throwable t) {
					if (!running || wasInterrupted(t)) {
						notifyReadyWaiters();
						logger.debug("Interrupted while rebuilding join estimator", t);
						break;
					}
					logger.error("Error while rebuilding join estimator", t);
				}

				if (!waitForRefreshDelay()) {
					break;
				}

				logger.debug("RdfJoinEstimator: Rebuilt join estimator.");
			}
		}, REFRESH_THREAD_NAME);

		refresher.setDaemon(true);
		refresher.start();
	}

	private synchronized long rebuildIfStillRequired() {
		if (!rebuildRequired.get()) {
			return 0L;
		}
		return rebuild();
	}

	private synchronized long rebuildIfNotReady() {
		if (isReadyNonBlocking()) {
			return 0L;
		}
		return rebuild();
	}

	private boolean waitForBackgroundRebuildQuietPeriod() {
		while (running) {
			long waitMillis = millisUntilStoreMutationQuiet();
			if (waitMillis <= 0L) {
				return true;
			}
			if (!waitForRefreshDelay(waitMillis)) {
				return false;
			}
		}
		return false;
	}

	private long millisUntilStoreMutationQuiet() {
		long lastMutationMillis = lastStoreMutationMillis.get();
		if (lastMutationMillis <= 0L) {
			return 0L;
		}
		long quietMillis = System.currentTimeMillis() - lastMutationMillis;
		if (quietMillis >= BACKGROUND_REBUILD_LOAD_QUIET_MILLIS) {
			return 0L;
		}
		return BACKGROUND_REBUILD_LOAD_QUIET_MILLIS - Math.max(0L, quietMillis);
	}

	private boolean waitForRefreshDelay() {
		return waitForRefreshDelay(refreshSleepMillis);
	}

	private boolean waitForRefreshDelay(long requestedMillis) {
		if (refreshSleepMillis <= 0L) {
			if (requestedMillis <= 0L) {
				Thread.yield();
				return true;
			}
			synchronized (readyMonitor) {
				try {
					readyMonitor.wait(requestedMillis);
					return true;
				} catch (InterruptedException e) {
					Thread.currentThread().interrupt();
					return false;
				}
			}
		}
		long waitMillis = requestedMillis <= 0L ? refreshSleepMillis : Math.min(refreshSleepMillis, requestedMillis);
		if (waitMillis <= 0L) {
			Thread.yield();
			return true;
		}
		synchronized (readyMonitor) {
			try {
				readyMonitor.wait(waitMillis);
				return true;
			} catch (InterruptedException e) {
				Thread.currentThread().interrupt();
				return false;
			}
		}
	}

	public void stop() {
		running = false;
		Thread refreshThread = refresher;
		if (refreshThread != null) {
			refreshThread.interrupt();
			if (Thread.currentThread() == refreshThread) {
				return;
			}
			try {
				while (refreshThread.isAlive()) {
					refreshThread.join(250L);
				}
			} catch (InterruptedException e) {
				Thread.currentThread().interrupt();
			} finally {
				refresher = null;
			}
		}
	}

	public void close() {
		flushPendingIncremental();
		stop();
		try {
			persistIfDirty();
		} finally {
			shutdownAsyncIncrementalIngest();
			clearStateSnapshots();
			clearEstimateCache();
			closePersistenceStore();
		}
	}

	private void clearStateSnapshots() {
		synchronized (bufA) {
			bufA.clear();
		}
		synchronized (bufB) {
			bufB.clear();
		}
	}

	private void closePersistenceStore() {
		SketchEstimatorPersistenceStore store = persistenceStore;
		persistenceStore = null;
		if (store != null) {
			store.close();
		}
	}

	private void shutdownAsyncIncrementalIngest() {
		if (incrementalIdleMonitor != null) {
			incrementalIdleMonitor.cancel(false);
		}
		incrementalIdleMonitorExecutor.shutdownNow();
		asyncIncrementalExecutor.shutdown();
		try {
			while (!asyncIncrementalExecutor.awaitTermination(1, TimeUnit.SECONDS)) {
				logger.debug("Waiting for join estimator async ingestion executor to terminate");
			}
		} catch (InterruptedException e) {
			Thread.currentThread().interrupt();
			asyncIncrementalExecutor.shutdownNow();
		}
		ingestPartitionExecutor.shutdown();
		try {
			while (!ingestPartitionExecutor.awaitTermination(1, TimeUnit.SECONDS)) {
				logger.debug("Waiting for join estimator partition ingestion workers to terminate");
			}
		} catch (InterruptedException e) {
			Thread.currentThread().interrupt();
			failPendingPartitionWork(e);
		}
		List<Runnable> skipped = ingestPartitionExecutor.shutdownNow();
		if (!skipped.isEmpty()) {
			failPendingPartitionWork(new RejectedExecutionException("Partition ingestion executor stopped"));
		}
	}

	/* ────────────────────────────────────────────────────────────── */
	/* Rebuild */
	/* ────────────────────────────────────────────────────────────── */

	/**
	 * Rebuild the inactive buffer from scratch (blocking). <br>
	 * Readers stay lock‑free; once complete a single volatile store publishes the fresh {@code State}.
	 *
	 * @return number of statements scanned.
	 */
	public synchronized long rebuild() {
		flushPendingIncremental();
		clearEstimateCacheIfPopulated();
		clearPositiveReadinessCache();
		long requestVersion = rebuildRequestVersion.get();
		long sizeBeforeRebuild = approxStoreSize.get();
		boolean keepRebuildRequiredOnEarlyStop = rebuildRequired.get() || !isReadyNonBlocking();

		boolean rebuildIntoA = !usingA; // remember before toggling

		State tgt = rebuildIntoA ? bufA : bufB;
		byte previousCurrentSlot = slotByte(slotOf(current));
		byte targetSlot = slotByte(slotOf(tgt));
		clearSlotPersistence(targetSlot);
		slotGenerations[targetSlot]++;
		tgt.clear(); // wipe everything (add + del)
		rebuildEpoch.incrementAndGet(); // mark rebuild in progress (odd epoch)
		long seen = 0L;
		long startMillis = System.currentTimeMillis();
		long lastThroughputCheckSeen = 0L;
		long lastThroughputPrintMillis = startMillis;
		long lastThroughputPrintSeen = 0L;
		long lastLoggedRebuildMillion = -1L;
		boolean stoppedEarly = false;
		String targetBuffer = rebuildIntoA ? "bufA" : "bufB";
		logger.info(
				"RdfJoinEstimator: Rebuilding sketches started: targetBuffer={}, targetSlot={}, previousCurrentSlot={}, rebuildRequestVersion={}",
				targetBuffer, targetSlot, previousCurrentSlot, requestVersion);
		try {
			try (CloseableIteration<? extends Statement> it = statementSource.getStatements(null, null, null)) {
				IngestEvent[] rebuildBatch = new IngestEvent[Math.min(REBUILD_BATCH_SIZE, memoryMonitorCheckInterval)];
				int rebuildBatchSize = 0;
				int rebuildMemoryCheckCountdown = memoryMonitorCheckInterval;

				while (it.hasNext()) {
					if (Thread.currentThread().isInterrupted() || !running && Thread.currentThread() == refresher
							|| Thread.currentThread() == refresher && !isRebuildAllowed()) {
						stoppedEarly = true;
						break;
					}
					Statement st = it.next();
					rebuildMemoryCheckCountdown--;
					if (rebuildMemoryCheckCountdown <= 0) {
						rebuildMemoryCheckCountdown = memoryMonitorCheckInterval;
						if (!hasMemoryForMonitoredOperations(rebuildBatch.length)) {
							return stopRebuildUnderMemoryPressure(tgt, targetBuffer, targetSlot, seen, startMillis);
						}
					}
					IngestEvent event = toIngestEvent(st, false);
					if (event == null) {
						continue;
					}
					rebuildBatch[rebuildBatchSize] = event;
					rebuildBatchSize++;
					if (rebuildBatchSize == rebuildBatch.length) {
						ingestRebuildBatch(tgt, rebuildBatch, rebuildBatchSize);
						long ingested = seen + 1L;
						rebuildBatchSize = 0;
						if (shouldCheckRebuildThroughput(ingested, lastThroughputCheckSeen)) {
							lastThroughputCheckSeen = ingested;
							long nowMillis = System.currentTimeMillis();
							if (shouldPrintRebuildThroughput(ingested, lastThroughputPrintSeen, nowMillis,
									lastThroughputPrintMillis)) {
								printRebuildThroughput(targetBuffer, ingested, lastThroughputPrintSeen, nowMillis,
										lastThroughputPrintMillis, startMillis);
								lastThroughputPrintMillis = nowMillis;
								lastThroughputPrintSeen = ingested;
							}
						}
						if (logger.isDebugEnabled()) {
							long seenMillion = seen / 1_000_000;
							if (seenMillion != lastLoggedRebuildMillion) {
								lastLoggedRebuildMillion = seenMillion;
								logger.debug(
										"RdfJoinEstimator: Rebuilding {}, seen {} million triples so far. Elapsed: {} s.",
										targetBuffer,
										seenMillion,
										(System.currentTimeMillis() - startMillis) / 1000);
							}
						}
					}

					seen++;

					if (throttleEveryN > 0 && throttleMillis > 0 && seen % throttleEveryN == 0) {
						try {
							Thread.sleep(throttleMillis);
						} catch (InterruptedException ie) {
							Thread.currentThread().interrupt();
							stoppedEarly = true;
							break;
						}
					}

				}
				if (!stoppedEarly && seen > 0) {
					if (rebuildBatchSize > 0) {
						ingestRebuildBatch(tgt, rebuildBatch, rebuildBatchSize);
						if (shouldCheckRebuildThroughput(seen, lastThroughputCheckSeen)) {
							long nowMillis = System.currentTimeMillis();
							if (shouldPrintRebuildThroughput(seen, lastThroughputPrintSeen, nowMillis,
									lastThroughputPrintMillis)) {
								printRebuildThroughput(targetBuffer, seen, lastThroughputPrintSeen, nowMillis,
										lastThroughputPrintMillis, startMillis);
							}
						}
					}
				}
			} catch (SketchStatementSourceException e) {
				if (Thread.currentThread() == refresher) {
					stoppedEarly = true;
				} else {
					throw e;
				}
			}

			if (stoppedEarly) {
				return stopRebuildEarly(tgt, targetBuffer, targetSlot, seen, startMillis,
						keepRebuildRequiredOnEarlyStop);
			}

			synchronized (tgt) {
				markRebuiltSketchesDirty(tgt);
			}
			current = tgt; // single volatile write → visible to all readers
			long rebuiltRows = seen;
			seenTriples = approxStoreSize.updateAndGet(
					currentSize -> storeSizeAfterRebuild(rebuiltRows, sizeBeforeRebuild, currentSize));
			sketchesLoaded = true;
			clearRebuildRequiredIfUnchanged(requestVersion);
			markPersistenceMutation();
			indexDirty.set(true);
			usingA = !usingA;
			synchronized (sketchCacheLock) {
				cacheDirectory.clearDirtyForSlot(previousCurrentSlot);
			}

			// staleness: publish times & reset churn sampler
			lastRebuildPublishMs = System.currentTimeMillis();
			churnSampler.reset();
			synchronized (incrementalBufferLock) {
				exactIncrementalUpdatesDropped = false;
				resetIncrementalQueueGrowthLocked();
			}

			logger.info(
					"RdfJoinEstimator: Rebuilding sketches finished: targetBuffer={}, targetSlot={}, previousCurrentSlot={}, scannedTriples={}, stoppedEarly={}, elapsedMillis={}",
					targetBuffer, targetSlot, previousCurrentSlot, seen, stoppedEarly,
					elapsedMillisSince(startMillis));
			return seen;
		} finally {
			if ((rebuildEpoch.get() & 1L) != 0L) {
				rebuildEpoch.incrementAndGet(); // mark rebuild complete (even epoch)
			}
			notifyReadyWaiters();
		}
	}

	static boolean shouldPrintRebuildThroughput(long ingestedStatements, long lastPrintedStatements, long nowMillis,
			long lastPrintedMillis) {
		return ingestedStatements - lastPrintedStatements >= REBUILD_THROUGHPUT_STDOUT_INTERVAL_STATEMENTS
				&& nowMillis - lastPrintedMillis >= REBUILD_THROUGHPUT_STDOUT_INTERVAL_MILLIS;
	}

	static boolean shouldCheckRebuildThroughput(long ingestedStatements, long lastCheckedStatements) {
		return ingestedStatements - lastCheckedStatements >= REBUILD_THROUGHPUT_CHECK_INTERVAL_STATEMENTS;
	}

	private static void printRebuildThroughput(String targetBuffer, long ingestedStatements, long lastPrintedStatements,
			long nowMillis, long lastPrintedMillis, long startMillis) {
		long elapsedSinceLastPrintMillis = Math.max(1L, nowMillis - lastPrintedMillis);
		long ingestedSinceLastPrint = ingestedStatements - lastPrintedStatements;
		long statementsPerSecond = Math.round(ingestedSinceLastPrint * 1000.0d / elapsedSinceLastPrintMillis);
		logger.info(
				"RdfJoinEstimator: Rebuilding {}, ingested {} statements into sketches, {} statements/s since last print. Elapsed: {} s.",
				targetBuffer, ingestedStatements, statementsPerSecond, (nowMillis - startMillis) / 1000L);
	}

	private long stopRebuildEarly(State target, String targetBuffer, byte targetSlot, long seen, long startMillis,
			boolean keepRebuildRequired) {
		synchronized (target) {
			target.clear();
		}
		if (keepRebuildRequired) {
			markRebuildRequired();
		}
		logger.debug(
				"RdfJoinEstimator: Rebuilding sketches deferred: targetBuffer={}, targetSlot={}, scannedTriples={}, elapsedMillis={}",
				targetBuffer, targetSlot, seen, elapsedMillisSince(startMillis));
		return seen;
	}

	private long stopRebuildUnderMemoryPressure(State target, String targetBuffer, byte targetSlot, long seen,
			long startMillis) {
		synchronized (target) {
			target.clear();
		}
		markRebuildRequired();
		logger.info(
				"RdfJoinEstimator: Rebuilding sketches stopped by memory monitor: targetBuffer={}, targetSlot={}, scannedTriples={}, elapsedMillis={}",
				targetBuffer, targetSlot, seen, elapsedMillisSince(startMillis));
		return seen;
	}

	/* ────────────────────────────────────────────────────────────── */
	/* Incremental updates */
	/* ────────────────────────────────────────────────────────────── */

	public void addStatement(Statement st) {
		Objects.requireNonNull(st);
		clearEstimateCacheIfPopulated();
		recordStoreMutationMillis();
		if (!isReadyForIncrementalUpdates()) {
			recordStoreSizeDelta(1L, 0L);
			return;
		}

		seenTriples = approxStoreSize.incrementAndGet();
		enqueueIncrementalStatement(st, false);
		markPersistenceMutation();
	}

	public void addStatements(List<? extends Statement> statements) {
		Objects.requireNonNull(statements);
		if (statements.isEmpty()) {
			return;
		}
		clearEstimateCacheIfPopulated();
		recordStoreMutationMillis();
		if (!isReadyForIncrementalUpdates()) {
			recordStoreSizeDelta(statements.size(), 0L);
			return;
		}

		seenTriples = approxStoreSize.updateAndGet(current -> applyStoreSizeDelta(current, statements.size(), 0L));
		enqueueIncrementalStatements(statements, false);
		markPersistenceMutation();
	}

	public void addStatement(Resource s, IRI p, Value o, Resource c) {
		addStatement(statementSource.getValueFactory().createStatement(s, p, o, c));
	}

	public void addStatement(Resource s, IRI p, Value o) {
		addStatement(s, p, o, null);
	}

	/**
	 * Records committed store-size changes when exact incremental sketch updates are intentionally deferred.
	 */
	public void recordStoreSizeDelta(long additions, long deletions) {
		if (additions < 0 || deletions < 0) {
			throw new IllegalArgumentException("Store-size deltas must be non-negative");
		}
		if (additions == 0 && deletions == 0) {
			return;
		}
		clearEstimateCacheIfPopulated();
		recordStoreMutationMillis();
		approxStoreSize.updateAndGet(current -> applyStoreSizeDelta(current, additions, deletions));
		if (sketchStrategy == SketchStrategy.OMNI && deletions > 0L) {
			markOmniEstimatorHasDeletes(bufA);
			markOmniEstimatorHasDeletes(bufB);
			clearPositiveReadinessCache();
			invalidatePersistedSketchSnapshotAfterOmniDelete();
		}
		markRebuildRequired();
		notifyReadyWaiters();
	}

	public void deleteStatement(Statement st) {
		Objects.requireNonNull(st);
		clearEstimateCacheIfPopulated();
		recordStoreMutationMillis();
		if (sketchStrategy == SketchStrategy.OMNI) {
			markOmniDeleteRequiresRebuild(1L);
			return;
		}
		if (!isReadyForIncrementalUpdates()) {
			recordStoreSizeDelta(0L, 1L);
			return;
		}

		seenTriples = approxStoreSize.updateAndGet(v -> Math.max(0, v - 1));
		enqueueIncrementalStatement(st, true);
		markPersistenceMutation();
	}

	public void deleteStatements(List<? extends Statement> statements) {
		Objects.requireNonNull(statements);
		if (statements.isEmpty()) {
			return;
		}
		clearEstimateCacheIfPopulated();
		recordStoreMutationMillis();
		if (sketchStrategy == SketchStrategy.OMNI) {
			markOmniDeleteRequiresRebuild(statements.size());
			return;
		}
		if (!isReadyForIncrementalUpdates()) {
			recordStoreSizeDelta(0L, statements.size());
			return;
		}

		seenTriples = approxStoreSize.updateAndGet(v -> Math.max(0, v - statements.size()));
		enqueueIncrementalStatements(statements, true);
		markPersistenceMutation();
	}

	private void markPersistenceMutation() {
		persistenceMutationCycle.mutationEnqueued();
		dirty.set(true);
	}

	private static long applyStoreSizeDelta(long current, long additions, long deletions) {
		long afterAdditions = current > Long.MAX_VALUE - additions ? Long.MAX_VALUE : current + additions;
		return Math.max(0L, afterAdditions - Math.min(afterAdditions, deletions));
	}

	private void recordStoreMutationMillis() {
		lastStoreMutationMillis.set(System.currentTimeMillis());
	}

	private void markOmniDeleteRequiresRebuild(long deletions) {
		if (deletions <= 0L) {
			return;
		}
		seenTriples = approxStoreSize.updateAndGet(current -> applyStoreSizeDelta(current, 0L, deletions));
		markOmniEstimatorHasDeletes(bufA);
		markOmniEstimatorHasDeletes(bufB);
		markRebuildRequired();
		clearPositiveReadinessCache();
		invalidatePersistedSketchSnapshotAfterOmniDelete();
		notifyReadyWaiters();
	}

	private static void markOmniEstimatorHasDeletes(State state) {
		if (state != null && state.sketchStrategy == SketchStrategy.OMNI) {
			synchronized (state) {
				state.omniJoinEstimatorHasDeletes = true;
			}
		}
	}

	private void invalidatePersistedSketchSnapshotAfterOmniDelete() {
		persistenceMutationCycle.markCurrentPersisted();
		dirty.set(false);
		indexDirty.set(false);
		clearPersistedSketchDirectory();
		if (!persistenceEnabled || persistenceFile == null) {
			return;
		}
		try {
			SketchEstimatorPersistenceStore store = persistenceStore;
			if (store != null) {
				store.reset();
			} else {
				Files.deleteIfExists(persistenceFile.toAbsolutePath().normalize().resolve("metadata.bin"));
			}
		} catch (IOException e) {
			logger.warn("Failed to invalidate stale OMNI join estimator snapshot at {}", persistenceFile, e);
		}
	}

	private static long storeSizeAfterRebuild(long rebuiltRows, long sizeBeforeRebuild, long currentSize) {
		if (currentSize >= sizeBeforeRebuild) {
			return applyStoreSizeDelta(rebuiltRows, currentSize - sizeBeforeRebuild, 0L);
		}
		return applyStoreSizeDelta(rebuiltRows, 0L, sizeBeforeRebuild - currentSize);
	}

	private boolean isReadyForIncrementalUpdates() {
		if (rebuildRequired.get()) {
			return false;
		}
		if (sketchesLoaded) {
			// applyIncrementalBatch mirrors exact deltas into both buffers while rebuildEpoch is odd.
			return true;
		}
		if ((rebuildEpoch.get() & 1L) != 0L) {
			return false;
		}
		State snap = current;
		synchronized (snap) {
			return hasRequiredActiveSketchGroups(snap);
		}
	}

	public boolean canAcceptIncrementalUpdatesNonBlocking() {
		if (!isReadyForIncrementalUpdates()) {
			return false;
		}
		synchronized (incrementalBufferLock) {
			if (!isReadyForIncrementalUpdates()) {
				return false;
			}
			if (exactIncrementalUpdatesDropped) {
				markIncrementalRebuildRequiredLocked();
				return false;
			}
			if (shouldCheckIncrementalQueueMemoryLocked(1) && !hasMemoryForExactStatementQueuesLocked(1L)) {
				dropExactIncrementalUpdatesLocked();
				return false;
			}
			return true;
		}
	}

	private void enqueueIncrementalStatement(Statement statement, boolean isDelete) {
		rethrowAsyncIncrementalFailure();
		StatementUpdateBatch batch = null;
		synchronized (incrementalBufferLock) {
			lastIncrementalStatementMillis = System.currentTimeMillis();
			if (exactIncrementalUpdatesDropped) {
				markIncrementalRebuildRequiredLocked();
				return;
			}
			if (shouldCheckIncrementalQueueMemoryLocked(1) && !hasMemoryForExactStatementQueuesLocked(1L)) {
				dropExactIncrementalUpdatesLocked();
				return;
			}
			StatementUpdateQueue active = activeStatementQueue();
			active.add(new StatementUpdateChunk(List.of(statement), 0, 1, isDelete));
			if (active.updateCount >= active.limit) {
				batch = rotateFullStatementQueueLocked();
			}
		}
		if (batch != null) {
			submitIncrementalStatementBatch(batch);
		}
	}

	private void enqueueIncrementalStatements(List<? extends Statement> statements, boolean isDelete) {
		Objects.requireNonNull(statements);
		rethrowAsyncIncrementalFailure();
		for (Statement statement : statements) {
			Objects.requireNonNull(statement);
		}
		StatementUpdateBatch batch = null;
		synchronized (incrementalBufferLock) {
			lastIncrementalStatementMillis = System.currentTimeMillis();
			if (exactIncrementalUpdatesDropped) {
				markIncrementalRebuildRequiredLocked();
				return;
			}
			int updateCount = statements.size();
			if (shouldCheckIncrementalQueueMemoryLocked(updateCount)
					&& !hasMemoryForExactStatementQueuesLocked(updateCount)) {
				dropExactIncrementalUpdatesLocked();
				return;
			}
			StatementUpdateQueue active = activeStatementQueue();
			active.add(new StatementUpdateChunk(statements, 0, statements.size(), isDelete));
			if (active.updateCount >= active.limit) {
				batch = rotateFullStatementQueueLocked();
			}
		}
		if (batch != null) {
			submitIncrementalStatementBatch(batch);
		}
	}

	private IngestEvent toIngestEvent(Statement statement, boolean isDelete) {
		try {
			String s = str(statement.getSubject());
			String p = str(statement.getPredicate());
			String o = str(statement.getObject());
			String c = str(statement.getContext());
			boolean omniRuntime = sketchStrategy == SketchStrategy.OMNI;
			int si = omniRuntime ? 0 : hash(Component.S, s);
			int pi = omniRuntime ? 0 : hash(Component.P, p);
			int oi = omniRuntime ? 0 : hash(Component.O, o);
			int ci = omniRuntime ? 0 : hash(Component.C, c);

			long hs = valueFingerprint(s);
			long hp = valueFingerprint(p);
			long ho = valueFingerprint(o);
			long hc = valueFingerprint(c);
			long sig = quadFingerprint(hs, hp, ho, hc);
			long thetaHs = omniRuntime ? omniHash(hs) : thetaHash(hs);
			long thetaHp = omniRuntime ? omniHash(hp) : thetaHash(hp);
			long thetaHo = omniRuntime ? omniHash(ho) : thetaHash(ho);
			long thetaHc = omniRuntime ? omniHash(hc) : thetaHash(hc);
			long thetaSig = omniRuntime ? omniHash(sig) : thetaHash(sig);
			long spKey = omniRuntime ? 0L : pairKey(si, pi);
			long scKey = omniRuntime ? 0L : pairKey(si, ci);
			long poKey = omniRuntime ? 0L : pairKey(pi, oi);
			long pcKey = omniRuntime ? 0L : pairKey(pi, ci);
			long ocKey = omniRuntime ? 0L : pairKey(oi, ci);
			SketchTermKey predicateKey = omniRuntime ? sketchKeyProvider.predicateKey(statement.getPredicate()) : null;
			SketchTermKey contextKey = omniRuntime ? sketchKeyProvider.contextKey(statement.getContext()) : null;
			return new IngestEvent(isDelete, si, pi, oi, ci, predicateKey, contextKey, thetaHs, thetaHp, thetaHo,
					thetaHc, thetaSig, spKey, scKey, poKey, pcKey, ocKey);
		} catch (NullPointerException npe) {
			return null;
		}
	}

	private void flushPendingIncremental() {
		rethrowAsyncIncrementalFailure();
		waitForAsyncIncrementalBatches();
		while (true) {
			StatementUpdateBatch batch;
			synchronized (incrementalBufferLock) {
				batch = drainActiveStatementQueueLocked();
				if (batch == null) {
					break;
				}
			}
			applyStatementUpdateBatch(batch);
			waitForAsyncIncrementalBatches();
		}
		waitForAsyncIncrementalBatches();
		rethrowAsyncIncrementalFailure();
	}

	private void flushIdleIncrementalStatementQueue() {
		if (asyncIncrementalFailure.get() != null) {
			return;
		}
		StatementUpdateBatch batch = null;
		synchronized (incrementalBufferLock) {
			long lastInsert = lastIncrementalStatementMillis;
			if (lastInsert == 0L || System.currentTimeMillis() - lastInsert < incrementalQueueIdleResetMillis) {
				return;
			}
			StatementUpdateQueue active = activeStatementQueue();
			if (active.updateCount > 0) {
				StatementUpdateQueue other = otherStatementQueue();
				if (!other.isReusable()) {
					return;
				}
				batch = drainActiveStatementQueueLocked();
				activeStatementQueueIndex = otherStatementQueueIndex();
				activeStatementQueue().limit = incrementalQueueInitialLimit;
			}
			if (activeStatementQueue().updateCount == 0) {
				resetIncrementalQueueGrowthLocked();
			}
			lastIncrementalStatementMillis = 0L;
		}
		if (batch != null) {
			submitIncrementalStatementBatch(batch);
		}
	}

	private StatementUpdateBatch rotateFullStatementQueueLocked() {
		StatementUpdateQueue other = otherStatementQueue();
		int requestedLimit = nextStatementQueueLimit;
		if (!other.isReusable()) {
			return rotateBackloggedStatementQueueLocked(other);
		}
		long requestedRetainedUpdates = saturatingAdd(retainedStatementUpdatesLocked(), requestedLimit);
		if (!hasMemoryForStatementUpdatesAfterGc(requestedRetainedUpdates)) {
			dropExactIncrementalUpdatesLocked();
			return null;
		}
		StatementUpdateBatch batch = drainActiveStatementQueueLocked();
		activeStatementQueueIndex = otherStatementQueueIndex();
		StatementUpdateQueue nextActive = activeStatementQueue();
		nextActive.limit = requestedLimit;
		nextStatementQueueLimit = saturatedDoubleQueueLimit(requestedLimit);
		return batch;
	}

	private StatementUpdateBatch rotateBackloggedStatementQueueLocked(StatementUpdateQueue other) {
		StatementUpdateQueue active = activeStatementQueue();
		int pressureLimit = Math.max(incrementalQueueInitialLimit, Math.min(active.limit, nextStatementQueueLimit));
		long requestedRetainedUpdates = saturatingAdd(retainedStatementUpdatesLocked(), pressureLimit);
		if (hasMemoryForStatementUpdatesAfterGc(requestedRetainedUpdates)) {
			StatementUpdateBatch batch = drainActiveDetachedStatementQueueLocked();
			active.limit = pressureLimit;
			nextStatementQueueLimit = pressureLimit;
			return batch;
		}
		if (!waitForReusableStatementQueueLocked(other, active.updateCount)) {
			dropExactIncrementalUpdatesLocked();
			return null;
		}
		requestedRetainedUpdates = saturatingAdd(retainedStatementUpdatesLocked(), pressureLimit);
		if (!hasMemoryForStatementUpdatesAfterGc(requestedRetainedUpdates)) {
			dropExactIncrementalUpdatesLocked();
			return null;
		}
		StatementUpdateBatch batch = drainActiveStatementQueueLocked();
		activeStatementQueueIndex = otherStatementQueueIndex();
		StatementUpdateQueue nextActive = activeStatementQueue();
		nextActive.limit = pressureLimit;
		nextStatementQueueLimit = pressureLimit;
		return batch;
	}

	private boolean waitForReusableStatementQueueLocked(StatementUpdateQueue queue, int blockedUpdates) {
		long remainingMillis = incrementalQueueBlockBudgetRemainingMillisLocked();
		if (remainingMillis <= 0L) {
			return queue.isReusable();
		}
		remainingMillis = Math.min(remainingMillis, INCREMENTAL_QUEUE_FULL_WAIT_MILLIS);
		long startMillis = System.currentTimeMillis();
		long deadlineMillis = saturatingAdd(startMillis, remainingMillis);
		while (!queue.isReusable() && remainingMillis > 0L) {
			try {
				incrementalBufferLock.wait(remainingMillis);
			} catch (InterruptedException e) {
				Thread.currentThread().interrupt();
				recordAsyncIncrementalFailure(e);
				throw new RuntimeException("Interrupted while waiting for incremental join-estimator queue", e);
			}
			remainingMillis = deadlineMillis - System.currentTimeMillis();
		}
		long blockedMillis = elapsedMillisSince(startMillis);
		if (blockedMillis > 0L) {
			recordIncrementalQueueBlockedMillisLocked(blockedUpdates, blockedMillis);
		}
		return queue.isReusable();
	}

	private long incrementalQueueBlockBudgetRemainingMillisLocked() {
		if (incrementalQueueBlockBudgetMillis == 0L) {
			return 0L;
		}
		long spent = incrementalQueueBlockedMillisInWindow;
		if (spent >= incrementalQueueBlockBudgetMillis) {
			return 0L;
		}
		return incrementalQueueBlockBudgetMillis - spent;
	}

	private void recordIncrementalQueueBlockedMillisLocked(int blockedUpdates, long blockedMillis) {
		incrementalQueueBlockedUpdatesInWindow += Math.max(1, blockedUpdates);
		incrementalQueueBlockedMillisInWindow = saturatingAdd(incrementalQueueBlockedMillisInWindow, blockedMillis);
		if (incrementalQueueBlockedUpdatesInWindow >= incrementalQueueBlockWindowUpdates) {
			if (incrementalQueueBlockedMillisInWindow > incrementalQueueBlockBudgetMillis) {
				dropExactIncrementalUpdatesLocked();
			}
			incrementalQueueBlockedUpdatesInWindow = 0;
			incrementalQueueBlockedMillisInWindow = 0L;
		}
	}

	private StatementUpdateBatch drainActiveStatementQueueLocked() {
		StatementUpdateQueue active = activeStatementQueue();
		if (active.updateCount == 0) {
			return null;
		}
		StatementUpdateChunk[] chunks = active.chunks.toArray(StatementUpdateChunk[]::new);
		int updateCount = active.updateCount;
		active.clear();
		return new StatementUpdateBatch(active, chunks, updateCount);
	}

	private StatementUpdateBatch drainActiveDetachedStatementQueueLocked() {
		StatementUpdateQueue active = activeStatementQueue();
		if (active.updateCount == 0) {
			return null;
		}
		StatementUpdateChunk[] chunks = active.chunks.toArray(StatementUpdateChunk[]::new);
		int updateCount = active.updateCount;
		active.clear();
		return new StatementUpdateBatch(null, chunks, updateCount);
	}

	private void submitIncrementalStatementBatch(StatementUpdateBatch batch) {
		if (batch == null || batch.updateCount == 0) {
			return;
		}
		incrementAsyncIncrementalBatchCount();
		asyncIncrementalUpdateCount.addAndGet(batch.updateCount);
		StatementUpdateQueue queue = batch.queue;
		if (queue != null) {
			synchronized (incrementalBufferLock) {
				queue.inFlightCount = batch.updateCount;
			}
		}
		Future<?> future;
		try {
			future = asyncIncrementalExecutor.submit(() -> {
				try {
					applyStatementUpdateBatch(batch);
				} catch (Throwable t) {
					recordAsyncIncrementalFailure(t);
				} finally {
					if (queue != null) {
						synchronized (incrementalBufferLock) {
							queue.inFlightCount = 0;
							incrementalBufferLock.notifyAll();
						}
					}
					asyncIncrementalUpdateCount.addAndGet(-batch.updateCount);
					completeAsyncIncrementalBatch();
				}
			});
		} catch (RejectedExecutionException e) {
			if (queue != null) {
				synchronized (incrementalBufferLock) {
					queue.inFlightCount = 0;
					dropExactIncrementalUpdatesLocked();
					incrementalBufferLock.notifyAll();
				}
			} else {
				synchronized (incrementalBufferLock) {
					dropExactIncrementalUpdatesLocked();
					incrementalBufferLock.notifyAll();
				}
			}
			asyncIncrementalUpdateCount.addAndGet(-batch.updateCount);
			completeAsyncIncrementalBatch();
			return;
		} catch (RuntimeException e) {
			if (queue != null) {
				synchronized (incrementalBufferLock) {
					queue.inFlightCount = 0;
					incrementalBufferLock.notifyAll();
				}
			}
			asyncIncrementalUpdateCount.addAndGet(-batch.updateCount);
			completeAsyncIncrementalBatch();
			recordAsyncIncrementalFailure(e);
			throw e;
		}
		if (queue != null) {
			synchronized (incrementalBufferLock) {
				queue.future = future;
			}
		}
		rethrowAsyncIncrementalFailure();
	}

	private void applyStatementUpdateBatch(StatementUpdateBatch batch) {
		if (batch.updateCount == 0) {
			return;
		}
		IngestEvent[] events = new IngestEvent[Math.min(batch.updateCount, INCREMENTAL_BATCH_SIZE)];
		int eventCount = 0;
		int remainingUpdates = batch.updateCount;
		int chunkIndex = 0;
		for (StatementUpdateChunk chunk : batch.chunks) {
			for (int i = chunk.from; i < chunk.to; i++) {
				Statement statement = chunk.statements.get(i);
				String s = str(statement.getSubject());
				String p = str(statement.getPredicate());
				String o = str(statement.getObject());
				String c = str(statement.getContext());
				if (chunk.isDelete) {
					churnSampler.recordDelete(s, p, o, c, samplingInterval());
				} else {
					churnSampler.recordAdd(s, p, o, c, samplingInterval());
				}
				IngestEvent event = toIngestEvent(statement, chunk.isDelete);
				remainingUpdates--;
				if (event == null) {
					continue;
				}
				events[eventCount++] = event;
				if (eventCount == events.length) {
					applyTransformedIncrementalChunk(new TransformedStatementChunk(chunkIndex++, events, eventCount,
							eventCount));
					events = new IngestEvent[Math.min(Math.max(remainingUpdates, 0), INCREMENTAL_BATCH_SIZE)];
					eventCount = 0;
				}
			}
		}
		if (eventCount > 0) {
			applyTransformedIncrementalChunk(new TransformedStatementChunk(chunkIndex, events, eventCount, eventCount));
		}
	}

	private boolean shouldCheckIncrementalQueueMemoryLocked(int updateCount) {
		incrementalQueueMemoryCheckCountdown -= Math.max(1, updateCount);
		if (incrementalQueueMemoryCheckCountdown > 0) {
			return false;
		}
		incrementalQueueMemoryCheckCountdown = memoryMonitorCheckInterval;
		return true;
	}

	private boolean hasMemoryForExactStatementQueuesLocked(long additionalUpdates) {
		return hasMemoryForStatementUpdatesAfterGc(saturatingAdd(retainedStatementUpdatesLocked(), additionalUpdates));
	}

	private long retainedStatementUpdatesLocked() {
		long retainedUpdates = 0L;
		for (StatementUpdateQueue queue : incrementalStatementQueues) {
			retainedUpdates += queue.updateCount;
		}
		return saturatingAdd(retainedUpdates, asyncIncrementalUpdateCount.get());
	}

	private boolean hasMemoryForStatementUpdatesAfterGc(long updateCount) {
		long estimatedStatementBytes = Math.max(incrementalQueueEstimatedStatementBytes,
				memoryMonitorEstimatedOperationBytes);
		return hasMemoryForEstimatedOperationsAfterGc(updateCount, estimatedStatementBytes);
	}

	private boolean hasMemoryForMonitoredOperations(long operationCount) {
		return hasMemoryForEstimatedOperationsAfterGc(operationCount, memoryMonitorEstimatedOperationBytes);
	}

	private boolean hasMemoryForEstimatedOperationsAfterGc(long operationCount, long estimatedOperationBytes) {
		if (hasMemoryForEstimatedOperations(operationCount, estimatedOperationBytes)) {
			return true;
		}
		System.gc();
		return hasMemoryForEstimatedOperations(operationCount, estimatedOperationBytes);
	}

	private boolean hasMemoryForEstimatedOperations(long operationCount, long estimatedOperationBytes) {
		Runtime runtime = Runtime.getRuntime();
		long maxMemory = runtime.maxMemory();
		if (maxMemory <= 0L || maxMemory == Long.MAX_VALUE) {
			return true;
		}
		long usedMemory = runtime.totalMemory() - runtime.freeMemory();
		long availableMemory = Math.max(0L, maxMemory - usedMemory);
		long reservedMemory = (long) (maxMemory * INCREMENTAL_QUEUE_MIN_FREE_MEMORY_RATIO);
		long estimatedQueueBytes = saturatingMultiply(operationCount, estimatedOperationBytes);
		return availableMemory > reservedMemory && availableMemory - reservedMemory >= estimatedQueueBytes;
	}

	private void dropExactIncrementalUpdatesLocked() {
		if (!exactIncrementalUpdatesDropped) {
			logger.info(
					"RdfJoinEstimator: Incremental exact update queue exceeded backlog or heap budget; marking sketches for rebuild");
		}
		for (StatementUpdateQueue queue : incrementalStatementQueues) {
			queue.clear();
		}
		exactIncrementalUpdatesDropped = true;
		markIncrementalRebuildRequiredLocked();
	}

	private void markIncrementalRebuildRequiredLocked() {
		markRebuildRequired();
		notifyReadyWaiters();
	}

	private StatementUpdateQueue activeStatementQueue() {
		return incrementalStatementQueues[activeStatementQueueIndex];
	}

	private StatementUpdateQueue otherStatementQueue() {
		return incrementalStatementQueues[otherStatementQueueIndex()];
	}

	private int otherStatementQueueIndex() {
		return 1 - activeStatementQueueIndex;
	}

	private void resetIncrementalQueueGrowthLocked() {
		for (StatementUpdateQueue queue : incrementalStatementQueues) {
			if (queue.isReusable() && queue.updateCount == 0) {
				queue.limit = incrementalQueueInitialLimit;
			}
		}
		nextStatementQueueLimit = saturatedDoubleQueueLimit(incrementalQueueInitialLimit);
	}

	private static int saturatedDoubleQueueLimit(int value) {
		if (value >= INCREMENTAL_QUEUE_MAX_LIMIT / 2) {
			return INCREMENTAL_QUEUE_MAX_LIMIT;
		}
		return Math.max(1, value << 1);
	}

	private void incrementAsyncIncrementalBatchCount() {
		synchronized (asyncIncrementalDrainLock) {
			asyncIncrementalBatchCount++;
		}
	}

	private void completeAsyncIncrementalBatch() {
		synchronized (asyncIncrementalDrainLock) {
			asyncIncrementalBatchCount--;
			asyncIncrementalDrainLock.notifyAll();
		}
	}

	private void waitForAsyncIncrementalBatches() {
		if (asyncIncrementalBatchCount == 0) {
			// this is good enough
			return;
		}

		synchronized (asyncIncrementalDrainLock) {
			while (asyncIncrementalBatchCount > 0) {
				if (asyncIncrementalFailure.get() != null) {
					break;
				}
				try {
					asyncIncrementalDrainLock.wait();
				} catch (InterruptedException e) {
					Thread.currentThread().interrupt();
					recordAsyncIncrementalFailure(e);
					throw new RuntimeException("Interrupted while waiting for incremental join-estimator ingestion", e);
				}
			}
		}
		rethrowAsyncIncrementalFailure();
	}

	private void recordAsyncIncrementalFailure(Throwable failure) {
		asyncIncrementalFailure.compareAndSet(null, failure);
		synchronized (asyncIncrementalDrainLock) {
			asyncIncrementalDrainLock.notifyAll();
		}
		synchronized (incrementalBufferLock) {
			incrementalBufferLock.notifyAll();
		}
	}

	private void rethrowAsyncIncrementalFailure() {
		Throwable failure = asyncIncrementalFailure.get();
		if (failure == null) {
			return;
		}
		switch (failure) {
			case Error error -> throw error;
			case RuntimeException runtimeException -> throw runtimeException;
			default -> {
			}
		}
		throw new RuntimeException("Asynchronous incremental join-estimator ingestion failed", failure);
	}

	private void applyTransformedIncrementalChunk(TransformedStatementChunk chunk) {
		if (chunk.eventCount == 0) {
			return;
		}
		if (sketchStrategy == SketchStrategy.OMNI) {
			applyIncrementalOmniBatch(chunk.events, chunk.eventCount);
			return;
		}
		BatchUpdateAccumulator[] updates = buildBatchUpdates(chunk);
		applyIncrementalBatchUpdates(updates, chunk.events, chunk.eventCount);
	}

	private void applyIncrementalBatch(IngestEvent[] batch, int batchSize) {
		if (batchSize == 0) {
			return;
		}
		if (sketchStrategy == SketchStrategy.OMNI) {
			applyIncrementalOmniBatch(batch, batchSize);
			return;
		}

		BatchUpdateAccumulator[] updates = buildBatchUpdates(batch, batchSize);
		applyIncrementalBatchUpdates(updates, batch, batchSize);
	}

	private void applyIncrementalOmniBatch(IngestEvent[] events, int eventCount) {
		while (true) {
			long epoch = rebuildEpoch.get();
			if ((epoch & 1L) != 0L) {
				synchronized (bufA) {
					updateOmniJoinEstimator(bufA, events, eventCount);
				}
				synchronized (bufB) {
					updateOmniJoinEstimator(bufB, events, eventCount);
				}
				return;
			}

			State target = current;
			synchronized (target) {
				if (rebuildEpoch.get() != epoch) {
					continue;
				}
				updateOmniJoinEstimator(target, events, eventCount);
				return;
			}
		}
	}

	private void applyIncrementalBatchUpdates(BatchUpdateAccumulator[] updates, IngestEvent[] events, int eventCount) {
		while (true) {
			long epoch = rebuildEpoch.get();
			if ((epoch & 1L) != 0L) {
				synchronized (bufA) {
					applyBatchUpdates(bufA, updates, events, eventCount);
				}
				synchronized (bufB) {
					applyBatchUpdates(bufB, updates, events, eventCount);
				}
				return;
			}

			State target = current;
			synchronized (target) {
				if (rebuildEpoch.get() != epoch) {
					continue;
				}
				applyBatchUpdates(target, updates, events, eventCount);
				return;
			}
		}
	}

	private void ingestBatch(State state, IngestEvent[] batch, int batchSize) {
		if (state.sketchStrategy == SketchStrategy.OMNI) {
			synchronized (state) {
				updateOmniJoinEstimator(state, batch, batchSize);
			}
			return;
		}
		BatchUpdateAccumulator[] updates = buildBatchUpdates(batch, batchSize);
		synchronized (state) {
			applyBatchUpdates(state, updates, batch, batchSize);
		}
	}

	private void ingestRebuildBatch(State state, IngestEvent[] batch, int batchSize) {
		if (batchSize == 0) {
			return;
		}
		ingestBatch(state, batch, batchSize);
	}

	private void applyBatchUpdates(State state, BatchUpdateAccumulator[] batchUpdates, IngestEvent[] events,
			int eventCount) {
		updateOmniJoinEstimator(state, events, eventCount);
		if (state.sketchStrategy == SketchStrategy.OMNI) {
			return;
		}
		byte slot = slotByte(slotOf(state));
		for (BatchUpdateAccumulator updates : batchUpdates) {
			updates.applyTo(this, state, slot);
		}
	}

	private void updateOmniJoinEstimator(State state, IngestEvent[] events, int eventCount) {
		OmniJoinEstimator estimator = state.omniJoinEstimator;
		if (estimator == null || events == null || eventCount <= 0) {
			return;
		}
		OmniJoinEstimator.Relation statements = estimator.relation(OMNI_RELATION_STATEMENT);
		OmniJoinEstimator.Relation subjectStar = estimator.relation(OMNI_RELATION_SUBJECT_STAR);
		OmniJoinEstimator.Relation tupleSurface = estimator.relation(OMNI_RELATION_TUPLE_SURFACE);
		OmniJoinEstimator.Relation edgeForward = estimator.relation(OMNI_RELATION_EDGE_FORWARD);
		OmniJoinEstimator.Relation edgeReverse = estimator.relation(OMNI_RELATION_EDGE_REVERSE);
		boolean ingestContextSurfaces = contextPairSketchesEnabled;
		for (int i = 0; i < eventCount; i++) {
			IngestEvent event = events[i];
			if (event == null) {
				continue;
			}
			if (event.isDelete) {
				state.omniJoinEstimatorHasDeletes = true;
				markRebuildRequired();
				clearPositiveReadinessCache();
				invalidatePersistedSketchSnapshotAfterOmniDelete();
				notifyReadyWaiters();
				continue;
			}
			long statementIdentifier = event.thetaSig;
			long subjectIdentifier = event.thetaHs;
			long subjectHash = event.thetaHs;
			long predicateHash = event.thetaHp;
			long objectHash = event.thetaHo;
			long contextHash = event.thetaHc;
			SketchTermKey predicateKey = event.predicateKey;
			SketchTermKey contextKey = event.contextKey;
			OmniWitnessCohortSelection cohortSelection = omniWitnessCohortSelection(state, subjectHash, objectHash);
			updateOmniStatic(statements, OMNI_COMPONENT_ATTRIBUTES[Component.S.ordinal()], subjectHash,
					statementIdentifier, cohortSelection, false);
			updateOmniStatic(statements, OMNI_COMPONENT_ATTRIBUTES[Component.P.ordinal()], predicateHash,
					statementIdentifier, cohortSelection, false);
			updateOmniStatic(statements, OMNI_COMPONENT_ATTRIBUTES[Component.O.ordinal()], objectHash,
					statementIdentifier, cohortSelection, false);
			if (ingestContextSurfaces) {
				updateOmniStatic(statements, OMNI_COMPONENT_ATTRIBUTES[Component.C.ordinal()], contextHash,
						statementIdentifier, cohortSelection, false);
			} else {
				statements.updateStaticTotalOnly(OMNI_COMPONENT_ATTRIBUTES[Component.C.ordinal()], contextHash,
						1.0d);
			}
			updateOmniStatic(subjectStar, OMNI_COMPONENT_ATTRIBUTES[Component.P.ordinal()], predicateHash,
					subjectIdentifier, cohortSelection, cohortSelection.subjectVertex());
			updateOmniStatic(subjectStar, OMNI_COMPONENT_ATTRIBUTES[Component.O.ordinal()], objectHash,
					subjectIdentifier, cohortSelection, cohortSelection.subjectVertex());
			updateOmniStatic(subjectStar, OMNI_SUBJECT_STAR_PO_ATTRIBUTE,
					OmniJoinEstimator.orderedTupleHash(predicateHash, objectHash), subjectIdentifier, cohortSelection,
					cohortSelection.subjectVertex());
			if (ingestContextSurfaces) {
				updateOmniStatic(subjectStar, OMNI_COMPONENT_ATTRIBUTES[Component.C.ordinal()], contextHash,
						subjectIdentifier, cohortSelection, cohortSelection.subjectVertex());
				updateOmniStatic(subjectStar, OMNI_SUBJECT_STAR_PC_ATTRIBUTE,
						OmniJoinEstimator.orderedTupleHash(predicateHash, contextHash), subjectIdentifier,
						cohortSelection, cohortSelection.subjectVertex());
				updateOmniStatic(subjectStar, OMNI_SUBJECT_STAR_OC_ATTRIBUTE,
						OmniJoinEstimator.orderedTupleHash(objectHash, contextHash), subjectIdentifier,
						cohortSelection, cohortSelection.subjectVertex());
				updateOmniStatic(subjectStar, OMNI_SUBJECT_STAR_POC_ATTRIBUTE,
						OmniJoinEstimator.orderedTupleHash(predicateHash, objectHash, contextHash), subjectIdentifier,
						cohortSelection, cohortSelection.subjectVertex());
			}
			updateOmniPredicate(edgeForward, predicateKey, subjectHash, objectHash, cohortSelection,
					cohortSelection.objectVertex());
			updateOmniPredicate(edgeReverse, predicateKey, objectHash, subjectHash, cohortSelection,
					cohortSelection.subjectVertex());
			updateOmniPredicate(edgeForward, predicateKey, OMNI_PREDICATE_EDGE_ANY_VALUE_HASH, objectHash,
					cohortSelection, cohortSelection.objectVertex());
			updateOmniPredicate(edgeReverse, predicateKey, OMNI_PREDICATE_EDGE_ANY_VALUE_HASH, subjectHash,
					cohortSelection, cohortSelection.subjectVertex());
			if (ingestContextSurfaces) {
				updateOmniPredicateContext(edgeForward, predicateKey, contextKey, subjectHash, objectHash,
						cohortSelection, cohortSelection.objectVertex());
				updateOmniPredicateContext(edgeReverse, predicateKey, contextKey, objectHash, subjectHash,
						cohortSelection, cohortSelection.subjectVertex());
				updateOmniPredicateContext(edgeForward, predicateKey, contextKey, OMNI_PREDICATE_EDGE_ANY_VALUE_HASH,
						objectHash, cohortSelection, cohortSelection.objectVertex());
				updateOmniPredicateContext(edgeReverse, predicateKey, contextKey, OMNI_PREDICATE_EDGE_ANY_VALUE_HASH,
						subjectHash, cohortSelection, cohortSelection.subjectVertex());
			}
			for (Component fixed : COMPONENT_VALUES) {
				if (!ingestContextSurfaces && fixed == Component.C) {
					continue;
				}
				long fixedHash = omniComponentHash(fixed.ordinal(), subjectHash, predicateHash, objectHash,
						contextHash);
				for (Component first : COMPONENT_VALUES) {
					if (first == fixed || (!ingestContextSurfaces && first == Component.C)) {
						continue;
					}
					for (Component second : COMPONENT_VALUES) {
						if (second == fixed || second.ordinal() <= first.ordinal()
								|| (!ingestContextSurfaces && second == Component.C)) {
							continue;
						}
						long tupleIdentifier = OmniJoinEstimator.orderedTupleHash(
								omniComponentHash(first.ordinal(), subjectHash, predicateHash, objectHash,
										contextHash),
								omniComponentHash(second.ordinal(), subjectHash, predicateHash, objectHash,
										contextHash));
						updateOmniStatic(tupleSurface,
								OMNI_TUPLE_SURFACE_ATTRIBUTES[fixed.ordinal()][first.ordinal()][second.ordinal()],
								fixedHash, tupleIdentifier, cohortSelection, false);
					}
				}
			}
		}
	}

	private OmniWitnessCohortSelection omniWitnessCohortSelection(State state, long subjectHash, long objectHash) {
		if (state == null || state.omniWitnessCohortBucketCount <= 0) {
			return OmniWitnessCohortSelection.NONE;
		}
		int bucketCount = state.omniWitnessCohortBucketCount;
		int bucketIndex = state.omniWitnessCohortBucketIndex;
		return new OmniWitnessCohortSelection(
				omniWitnessCohortSelected(subjectHash, OMNI_SUBJECT_WITNESS_COHORT_SEED, bucketCount, bucketIndex),
				omniWitnessCohortSelected(objectHash, OMNI_OBJECT_WITNESS_COHORT_SEED, bucketCount, bucketIndex),
				omniWitnessCohortSelected(subjectHash, OMNI_VERTEX_WITNESS_COHORT_SEED, bucketCount, bucketIndex),
				omniWitnessCohortSelected(objectHash, OMNI_VERTEX_WITNESS_COHORT_SEED, bucketCount, bucketIndex));
	}

	private static boolean omniWitnessCohortSelected(long hash, long roleSeed, int bucketCount, int bucketIndex) {
		if (bucketCount <= 0) {
			return false;
		}
		long mixed = mix64(hash ^ roleSeed);
		return Long.remainderUnsigned(mixed, bucketCount) == bucketIndex;
	}

	private static void updateOmniStatic(OmniJoinEstimator.Relation relation, byte attribute, long valueHash,
			long identifierHash, OmniWitnessCohortSelection cohortSelection, boolean vertexCohort) {
		relation.updateStatic(attribute, valueHash, identifierHash, 1.0d, cohortSelection.subject(),
				cohortSelection.object(), vertexCohort);
	}

	private static void updateOmniPredicate(OmniJoinEstimator.Relation relation, SketchTermKey predicateKey,
			long valueHash, long identifierHash, OmniWitnessCohortSelection cohortSelection, boolean vertexCohort) {
		relation.updatePredicate(predicateKey, valueHash, identifierHash, 1.0d, cohortSelection.subject(),
				cohortSelection.object(), vertexCohort);
	}

	private static void updateOmniPredicateContext(OmniJoinEstimator.Relation relation, SketchTermKey predicateKey,
			SketchTermKey contextKey, long valueHash, long identifierHash,
			OmniWitnessCohortSelection cohortSelection, boolean vertexCohort) {
		relation.updatePredicateContext(predicateKey, contextKey, valueHash, identifierHash, 1.0d,
				cohortSelection.subject(), cohortSelection.object(), vertexCohort);
	}

	private record OmniWitnessCohortSelection(boolean subject, boolean object, boolean subjectVertex,
			boolean objectVertex) {
		private static final OmniWitnessCohortSelection NONE = new OmniWitnessCohortSelection(false, false, false,
				false);
	}

	private static long omniComponentHash(int ordinal, long subjectHash, long predicateHash, long objectHash,
			long contextHash) {
		return switch (ordinal) {
		case 0 -> subjectHash;
		case 1 -> predicateHash;
		case 2 -> objectHash;
		case 3 -> contextHash;
		default -> throw new IllegalArgumentException("Unknown component ordinal: " + ordinal);
		};
	}

	private static void updateOmniSubjectStarComposite(OmniJoinEstimator.Relation subjectStar, long[] componentHashes,
			long subjectIdentifier, Component... components) {
		subjectStar.updateStatic(omniSubjectStarAttribute(components),
				omniCompositeValueHash(componentHashes, components), subjectIdentifier, 1.0d);
	}

	@SuppressWarnings("unchecked")
	private BatchUpdateAccumulator[] buildBatchUpdates(IngestEvent[] batch, int batchSize) {
		return buildBatchUpdates(new TransformedStatementChunk(0, batch, batchSize, batchSize));
	}

	@SuppressWarnings("unchecked")
	private BatchUpdateAccumulator[] buildBatchUpdates(TransformedStatementChunk chunk) {
		CompletableFuture<BatchUpdateAccumulator>[] futures = new CompletableFuture[enabledIngestPartitions.length];
		try {
			for (int i = 0; i < enabledIngestPartitions.length; i++) {
				CompletableFuture<BatchUpdateAccumulator> future = new CompletableFuture<>();
				futures[i] = future;
				putPartitionWork(i, new PartitionWork(chunk, enabledIngestPartitions[i], future));
			}
			BatchUpdateAccumulator[] updates = new BatchUpdateAccumulator[futures.length];
			for (int i = 0; i < futures.length; i++) {
				updates[i] = futures[i].get();
			}
			return updates;
		} catch (InterruptedException e) {
			Thread.currentThread().interrupt();
			throw new RuntimeException("Interrupted while preparing join-estimator batch", e);
		} catch (ExecutionException e) {
			throw new RuntimeException("Failed to prepare join-estimator batch", e.getCause());
		}
	}

	private void putPartitionWork(int partitionIndex, PartitionWork work) throws InterruptedException {
		long startMillis = System.currentTimeMillis();
		BlockingQueue<PartitionWork> queue = ingestPartitionQueues[partitionIndex];
		schedulePartitionDrain(partitionIndex);
		queue.put(work);
		schedulePartitionDrain(partitionIndex);
		long blockedMillis = elapsedMillisSince(startMillis);
		if (blockedMillis > 0L) {
			synchronized (incrementalBufferLock) {
				recordIncrementalQueueBlockedMillisLocked(work.chunk.updateCount, blockedMillis);
			}
		}
	}

	private BatchUpdateAccumulator buildBatchUpdates(IngestEvent[] batch, int batchSize, IngestPartition partition) {
		BatchUpdateAccumulator updates = new BatchUpdateAccumulator(Math.max(64, expectedBatchUpdates(batchSize,
				partition)));
		for (int i = 0; i < batchSize; i++) {
			IngestEvent event = batch[i];
			if (event == null) {
				continue;
			}
			accumulateIngestEvent(updates, event, partition);
		}
		return updates;
	}

	private int expectedBatchUpdates(int batchSize, IngestPartition partition) {
		if (partition == null) {
			return batchSize << 5;
		}
		if (partition == IngestPartition.SINGLES) {
			return expectedSingleBatchUpdates(batchSize);
		}
		return batchSize << 1;
	}

	private int expectedSingleBatchUpdates(int batchSize) {
		long batchEstimate = (long) batchSize << 3;
		long addressBound = ((long) maxBucketCount << 5) + 8L;
		return (int) Math.min(Integer.MAX_VALUE, Math.min(addressBound, Math.max(64L, batchEstimate)));
	}

	private void applyGroupedUpdate(State state, byte slot, int keyPrefix, int x, int y, long firstValue,
			long[] overflowValues, int valueCount) {
		if (valueCount == 0) {
			return;
		}
		byte recType = (byte) keyPrefix;
		if (recType == REC_SINGLE_PAIR_CPL) {
			return;
		}
		boolean isDelete = ((keyPrefix >>> 8) & 1) != 0;
		byte axisA = (byte) (keyPrefix >>> 16);
		byte axisB = (byte) (keyPrefix >>> 24);
		int storedKeyPrefix = recType == REC_GLOBAL_COMPONENT ? keyPrefix & ~DELETE_KEY_PREFIX_MASK : keyPrefix;
		int entryId;
		synchronized (sketchCacheLock) {
			entryId = cacheDirectory.findOrAdd(storedKeyPrefix, x, y);
		}
		boolean useDeleteSketch = recType != REC_GLOBAL_COMPONENT && isDelete;
		double delta = recType == REC_GLOBAL_COMPONENT ? signedDelta(isDelete) : 1.0d;
		FastAgmsBindingSummary sketch = getSketchForWrite(state, recType, useDeleteSketch, axisA, axisB, x, y,
				entryId);
		frequencyUpdateRaw(sketch, firstValue, delta);
		JoinFrequencySketch joinSketch = joinSketchForWrite(state, recType, entryId);
		if (joinSketch != null) {
			joinSketch.update(firstValue, 1L);
		}
		CountMinFrequencySketch countMinSketch = countMinSketchForWrite(state, recType, entryId);
		if (countMinSketch != null) {
			countMinSketch.update(firstValue, 1L);
		}
		for (int i = 1; i < valueCount; i++) {
			frequencyUpdateRaw(sketch, overflowValues[i - 1], delta);
			if (joinSketch != null) {
				joinSketch.update(overflowValues[i - 1], 1L);
			}
			if (countMinSketch != null) {
				countMinSketch.update(overflowValues[i - 1], 1L);
			}
		}
		markDirtyAndTouchResidentSketch(slot, entryId);
	}

	private void reserveResidentSketchCapacity(State state, int[] keyPrefixes, int[] xs, int[] ys, int count) {
		for (int i = 0; i < count;) {
			int keyPrefix = keyPrefixes[i];
			byte recType = (byte) keyPrefix;
			if (!isSparsePairRecordType(recType)) {
				i++;
				continue;
			}
			int from = i++;
			while (i < count && keyPrefixes[i] == keyPrefix) {
				i++;
			}
			PairBuild build = residentPairBuild(state, keyPrefix);
			if (build != null) {
				build.sparseArray(recType).reserveMissing(build, xs, ys, from, i);
			}
		}
	}

	private static boolean isSparsePairRecordType(byte recType) {
		return recType == REC_PAIR_TRIPLE || recType == REC_PAIR_COMP1 || recType == REC_PAIR_COMP2;
	}

	private static PairBuild residentPairBuild(State state, int keyPrefix) {
		boolean isDelete = ((keyPrefix >>> 8) & 1) != 0;
		Pair pair = PAIR_VALUES[(keyPrefix >>> 16) & 0xff];
		return isDelete ? state.delPairs.get(pair) : state.pairs.get(pair);
	}

	private void accumulateIngestEvent(BatchUpdateAccumulator updates, IngestEvent event, IngestPartition partition) {
		if (partition == null) {
			accumulateSingleUpdates(updates, event);
			accumulatePair(updates, Pair.SP, event.isDelete, event.spKey, event.thetaSig, event.thetaHo,
					event.thetaHc);
			if (contextPairSketchesEnabled) {
				accumulatePair(updates, Pair.SC, event.isDelete, event.scKey, event.thetaSig, event.thetaHp,
						event.thetaHo);
			}
			accumulatePair(updates, Pair.PO, event.isDelete, event.poKey, event.thetaSig, event.thetaHs,
					event.thetaHc);
			if (contextPairSketchesEnabled) {
				accumulatePair(updates, Pair.PC, event.isDelete, event.pcKey, event.thetaSig, event.thetaHs,
						event.thetaHo);
				accumulatePair(updates, Pair.OC, event.isDelete, event.ocKey, event.thetaSig, event.thetaHs,
						event.thetaHp);
			}
			return;
		}
		if (partition == IngestPartition.SP) {
			accumulatePair(updates, Pair.SP, event.isDelete, event.spKey, event.thetaSig, event.thetaHo,
					event.thetaHc);
			return;
		}
		switch (partition) {
		case SINGLES:
			accumulateSingleUpdates(updates, event);
			break;
		case SC:
			if (!contextPairSketchesEnabled) {
				break;
			}
			accumulatePair(updates, Pair.SC, event.isDelete, event.scKey, event.thetaSig, event.thetaHp,
					event.thetaHo);
			break;
		case PO:
			accumulatePair(updates, Pair.PO, event.isDelete, event.poKey, event.thetaSig, event.thetaHs,
					event.thetaHc);
			break;
		case PC:
			if (!contextPairSketchesEnabled) {
				break;
			}
			accumulatePair(updates, Pair.PC, event.isDelete, event.pcKey, event.thetaSig, event.thetaHs,
					event.thetaHo);
			break;
		case OC:
			if (!contextPairSketchesEnabled) {
				break;
			}
			accumulatePair(updates, Pair.OC, event.isDelete, event.ocKey, event.thetaSig, event.thetaHs,
					event.thetaHp);
			break;
		}
	}

	private void accumulateSingleUpdates(BatchUpdateAccumulator updates, IngestEvent event) {
		int deleteMask = event.isDelete ? DELETE_KEY_PREFIX_MASK : 0;
		int si = event.si;
		int pi = event.pi;
		int oi = event.oi;
		int ci = event.ci;
		long thetaHs = event.thetaHs;
		long thetaHp = event.thetaHp;
		long thetaHo = event.thetaHo;
		long thetaHc = event.thetaHc;
		long thetaSig = event.thetaSig;

		updates.add(SINGLE_TRIPLE_KEY_PREFIXES[COMPONENT_S_INDEX] | deleteMask, si, 0, thetaSig);
		updates.add(SINGLE_TRIPLE_KEY_PREFIXES[COMPONENT_P_INDEX] | deleteMask, pi, 0, thetaSig);
		updates.add(SINGLE_TRIPLE_KEY_PREFIXES[COMPONENT_O_INDEX] | deleteMask, oi, 0, thetaSig);
		updates.add(SINGLE_TRIPLE_KEY_PREFIXES[COMPONENT_C_INDEX] | deleteMask, ci, 0, thetaSig);

		updates.add(GLOBAL_COMPONENT_KEY_PREFIXES[COMPONENT_S_INDEX] | deleteMask, 0, 0, thetaHs);
		updates.add(GLOBAL_COMPONENT_KEY_PREFIXES[COMPONENT_P_INDEX] | deleteMask, 0, 0, thetaHp);
		updates.add(GLOBAL_COMPONENT_KEY_PREFIXES[COMPONENT_O_INDEX] | deleteMask, 0, 0, thetaHo);
		updates.add(GLOBAL_COMPONENT_KEY_PREFIXES[COMPONENT_C_INDEX] | deleteMask, 0, 0, thetaHc);

		updates.add(SINGLE_COMPLEMENT_KEY_PREFIXES[COMPONENT_S_INDEX][COMPONENT_P_INDEX] | deleteMask, si, 0, thetaHp);
		updates.add(SINGLE_COMPLEMENT_KEY_PREFIXES[COMPONENT_S_INDEX][COMPONENT_O_INDEX] | deleteMask, si, 0, thetaHo);
		updates.add(SINGLE_COMPLEMENT_KEY_PREFIXES[COMPONENT_S_INDEX][COMPONENT_C_INDEX] | deleteMask, si, 0, thetaHc);

		updates.add(SINGLE_COMPLEMENT_KEY_PREFIXES[COMPONENT_P_INDEX][COMPONENT_S_INDEX] | deleteMask, pi, 0, thetaHs);
		updates.add(SINGLE_COMPLEMENT_KEY_PREFIXES[COMPONENT_P_INDEX][COMPONENT_O_INDEX] | deleteMask, pi, 0, thetaHo);
		updates.add(SINGLE_COMPLEMENT_KEY_PREFIXES[COMPONENT_P_INDEX][COMPONENT_C_INDEX] | deleteMask, pi, 0, thetaHc);

		updates.add(SINGLE_COMPLEMENT_KEY_PREFIXES[COMPONENT_O_INDEX][COMPONENT_S_INDEX] | deleteMask, oi, 0, thetaHs);
		updates.add(SINGLE_COMPLEMENT_KEY_PREFIXES[COMPONENT_O_INDEX][COMPONENT_P_INDEX] | deleteMask, oi, 0, thetaHp);
		updates.add(SINGLE_COMPLEMENT_KEY_PREFIXES[COMPONENT_O_INDEX][COMPONENT_C_INDEX] | deleteMask, oi, 0, thetaHc);

		updates.add(SINGLE_COMPLEMENT_KEY_PREFIXES[COMPONENT_C_INDEX][COMPONENT_S_INDEX] | deleteMask, ci, 0, thetaHs);
		updates.add(SINGLE_COMPLEMENT_KEY_PREFIXES[COMPONENT_C_INDEX][COMPONENT_P_INDEX] | deleteMask, ci, 0, thetaHp);
		updates.add(SINGLE_COMPLEMENT_KEY_PREFIXES[COMPONENT_C_INDEX][COMPONENT_O_INDEX] | deleteMask, ci, 0, thetaHo);
	}

	private static void accumulatePair(BatchUpdateAccumulator updates, Pair pair, boolean isDelete, long key,
			long triple,
			long comp1, long comp2) {
		int x = (int) (key >>> 32);
		int y = (int) key;
		int pairIndex = pair.ordinal();
		int deleteMask = isDelete ? DELETE_KEY_PREFIX_MASK : 0;
		updates.add(PAIR_TRIPLE_KEY_PREFIXES[pairIndex] | deleteMask, x, y, triple);
		updates.add(PAIR_COMP1_KEY_PREFIXES[pairIndex] | deleteMask, x, y, comp1);
		updates.add(PAIR_COMP2_KEY_PREFIXES[pairIndex] | deleteMask, x, y, comp2);
	}

